const files = $json.files || [];
const taskDesc = $json.task?.description || $json.description || '';
const projectGoal = $json.project_goal || '';
const code = files.map(f => `### ${f.path}\n\`\`\`\n${f.content}\n\`\`\``).join('\n\n');
const context = (projectGoal || taskDesc) ? `\n\nProject Goal: ${projectGoal}\nCurrent Task: ${taskDesc}\n` : '';
return [{
  json: {
    model: $env.LOCAL_AI_MODEL || 'local-model',
    messages: [{
      role: 'user',
      content: `You are a Principal Software Architect. Review this code for quality.${context}\n\nCode:\n${code}\n\nSet job_complete to true ONLY if ALL requirements from the task description are implemented with working code. If the task asks for tests, there must be tests. If it asks for docs, there must be docs.\n\nReturn ONLY valid JSON (no markdown, no explanation):\n{"quality_score":number,"job_complete":boolean,"strengths":["..."],"areas_for_improvement":[{"area":"...","current_state":"...","target":"...","fix":"..."}],"recommendations":["..."]}`
    }],
    temperature: 0.3,
    top_p: 0.8,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 0.0,
    max_tokens: 2048
  }
}];

const raw = $json.choices[0].message.content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
// Strip markdown code block wrappers
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
// Try to extract JSON object if surrounded by prose
const jsonMatch = content.match(/\{[\s\S]*\}/);
let review;
try { review = JSON.parse(jsonMatch ? jsonMatch[0] : content); } catch (e) { review = { raw_output: content }; }
return [{ json: { quality_review: review, security_review: $('Execute Workflow Trigger').first().json.security_review, files: $('Execute Workflow Trigger').first().json.files } }];
